import math
import numpy as np

# Preprocessing functions
def tokenize(text):
    return text.lower().split()

def remove_stopwords(tokens, stopwords):
    return [token for token in tokens if token not in stopwords]

def stem(tokens):
    return [token[:-2] if len(token) > 2 else token for token in tokens]

def preprocess(text, stopwords):
    tokens = tokenize(text)
    tokens = remove_stopwords(tokens, stopwords)
    tokens = stem(tokens)
    return tokens

# Training function
def train_naive_bayes(corpus, labels, stopwords):
    class_counts = {}
    word_counts = {}
    total_words = 0

    for text, label in zip(corpus, labels):
        tokens = preprocess(text, stopwords)
        total_words += len(tokens)

        if label not in class_counts:
            class_counts[label] = 0
        class_counts[label] += 1

        for token in tokens:
            if label not in word_counts:
                word_counts[label] = {}
            if token not in word_counts[label]:
                word_counts[label][token] = 0
            word_counts[label][token] += 1

    # Calculate probabilities
    vocab_size = len(set([token for text in corpus for token in preprocess(text, stopwords)]))
    class_probs = {label: count / len(labels) for label, count in class_counts.items()}
    word_probs = {}

    for label in word_counts:
        word_probs[label] = {}
        for token, count in word_counts[label].items():
            word_probs[label][token] = (count + 1) / (sum(word_counts[label].values()) + vocab_size)

    return class_probs, word_probs, vocab_size

# Prediction function
def predict(text, class_probs, word_probs, vocab_size, stopwords):
    tokens = preprocess(text, stopwords)
    log_prob = {}
    for label in class_probs:
        log_prob[label] = math.log(class_probs[label])
        for token in tokens:
            if token in word_probs[label]:
                log_prob[label] += math.log(word_probs[label][token])
            else:
                log_prob[label] += math.log(1 / (vocab_size + 1))
    return max(log_prob, key=log_prob.get)

